// Edit all workflow settings here. No n8n ENV variable is required.
// 1) Paste sms.bd API key.
// 2) Paste Chatwoot base URL and API access token.
// 3) Change SMS footer settings as needed.

const CONFIG = {
  smsbdApiKey: 'PASTE_SMSBD_API_KEY_HERE',

  // Chatwoot base URL, without trailing slash.
  chatwootBaseUrl: 'https://app.unichat.com.bd',

  // Chatwoot profile/access token with permission to create conversation messages.
  chatwootApiToken: 'PASTE_CHATWOOT_API_ACCESS_TOKEN_HERE',

  // SMS footer option. Keep enabled true to append footer to every SMS.
  // Example footer: 'Company Name\nSupport: 096xxxxxxx'
  smsFooterEnabled: true,
  smsFooterText: 'Company Name\nSign: Your Team',

  // Optional sms.bd parameters. Leave blank if you do not use these.
  senderId: '',
  contentId: '',
  schedule: '',

  // Chatwoot response will be posted as private note to avoid SMS loop.
  chatwootPrivateReply: true
};

const item = $input.first().json;
return [{ json: { ...item, config: CONFIG } }];

// Extract Chatwoot payload, prevent loops, normalize phone, add optional SMS footer, and build sms.bd URL.

const item = $input.first().json;
const config = item.config || {};
const body = item.body && typeof item.body === 'object' && Object.keys(item.body).length ? item.body : item;

const event = body.event;
const isPrivate = body.private === true;
const contentType = body.content_type || body.content?.content_type;
const messageType = body.message_type;
const senderType = body.sender?.type || body.sender_type;

// Only send outgoing public text messages from Chatwoot agents/users.
// This prevents incoming customer messages or private notes from being sent as SMS.
const isOutgoing = messageType === 'outgoing' || messageType === 1 || messageType === '1';
const isText = !contentType || contentType === 'text';

// IMPORTANT: Send SMS only for Chatwoot message_created webhook events.
// If event is missing or anything else, stop the workflow.
if (event !== 'message_created') return [];
if (!isOutgoing) return [];
if (isPrivate) return [];
if (!isText) return [];
if (senderType === 'contact') return [];

const rawMessage = body.content || body.processed_message_content || body.messages?.[0]?.content || '';
const originalMessage = String(rawMessage).trim();

// Loop guard: do not process Chatwoot notes/status messages.
if (!originalMessage || originalMessage.startsWith('[SMS.BD]')) return [];

const sender = body.conversation?.meta?.sender || body.meta?.sender || {};
let rawPhone = sender.phone_number || sender.identifier || body.conversation?.contact_inbox?.source_id || '';
rawPhone = String(rawPhone).split('@')[0];

let to = rawPhone.replace(/[^0-9]/g, '');

// sms.bd accepts 8801XXXXXXXXX or 01XXXXXXXXX. Normalize to 880 format.
if (to.startsWith('00')) to = to.slice(2);
if (to.startsWith('0')) to = '88' + to;
if (to.startsWith('1') && to.length === 10) to = '880' + to;

const footerText = config.smsFooterEnabled && String(config.smsFooterText || '').trim()
  ? String(config.smsFooterText).trim()
  : '';
const finalMessage = footerText ? `${originalMessage}\n\n${footerText}` : originalMessage;

const accountId = body.account?.id || body.conversation?.account_id;
const conversationId = body.conversation?.id;
const chatwootBaseUrl = String(config.chatwootBaseUrl || '').replace(/\/$/, '');
const chatwootReplyUrl = `${chatwootBaseUrl}/api/v1/accounts/${accountId}/conversations/${conversationId}/messages`;

// n8n Code node sandbox may not support URLSearchParams in some versions.
// So we build the query string manually using encodeURIComponent.
function enc(value) {
  return encodeURIComponent(String(value ?? ''));
}

const queryParts = [];
queryParts.push(`api_key=${enc(config.smsbdApiKey || '')}`);
queryParts.push(`msg=${enc(finalMessage)}`);
queryParts.push(`to=${enc(to)}`);

if (String(config.schedule || '').trim()) queryParts.push(`schedule=${enc(String(config.schedule).trim())}`);
if (String(config.senderId || '').trim()) queryParts.push(`sender_id=${enc(String(config.senderId).trim())}`);
if (String(config.contentId || '').trim()) queryParts.push(`content_id=${enc(String(config.contentId).trim())}`);

const smsbdQueryString = queryParts.join('&');

const missingConfig = [];
if (!config.smsbdApiKey || String(config.smsbdApiKey).includes('PASTE_')) missingConfig.push('smsbdApiKey');
if (!config.chatwootApiToken || String(config.chatwootApiToken).includes('PASTE_')) missingConfig.push('chatwootApiToken');
if (!config.chatwootBaseUrl) missingConfig.push('chatwootBaseUrl');
if (!accountId) missingConfig.push('accountId from payload');
if (!conversationId) missingConfig.push('conversationId from payload');

return [
  {
    json: {
      config,
      accountId,
      conversationId,
      chatwootMessageId: body.id,
      contactId: sender.id,
      contactName: sender.name || '',
      rawPhone,
      to,
      originalMessage,
      footerText,
      finalMessage,
      inboxId: body.inbox?.id || body.conversation?.inbox_id,
      smsbdUrl: `https://api.sms.net.bd/sendsms?${smsbdQueryString}`,
      chatwootReplyUrl,
      missingConfig,
      validBangladeshMobile: /^8801[3-9]\d{8}$/.test(to),
      source: 'chatwoot'
    }
  }
];

// Build a clean Chatwoot private note from sms.bd response.
// Success note: "Message sent successfully."
// Error note: shows the exact sms.bd error code and meaning.
// This note never includes API keys, tokens, encoded URLs, or SMS body.

const original = $('Normalize + Add Footer').first().json;
const sms = $input.first().json || {};

const errorMessages = {
  0: 'Success. Everything worked as expected.',
  400: 'The request was rejected, due to a missing or invalid parameter.',
  403: "You don't have permissions to perform the request.",
  404: 'The requested resource not found.',
  405: 'Authorization required.',
  409: 'Unknown error occurred on Server end.',
  410: 'Account expired.',
  411: 'Reseller Account expired or suspended.',
  412: 'Invalid Schedule.',
  413: 'Invalid Sender ID.',
  414: 'Message is empty.',
  415: 'Message is too long.',
  416: 'No valid number found.',
  417: 'Insufficient balance.',
  420: 'Content Blocked.'
};

// If n8n HTTP node failed before receiving a JSON sms.bd response,
// continueOnFail normally gives an error object here.
const nodeError = sms.error && typeof sms.error === 'object' && (sms.error.message || sms.error.name);
let apiErrorCode = nodeError ? 'HTTP_REQUEST_FAILED' : sms.error;

// Some n8n/http versions may wrap response in body/data as JSON string.
let parsed = sms;
if (typeof sms.body === 'string') {
  try { parsed = JSON.parse(sms.body); } catch (e) {}
}
if (typeof sms.data === 'string') {
  try { parsed = JSON.parse(sms.data); } catch (e) {}
}
if (parsed && parsed !== sms && parsed.error !== undefined) {
  apiErrorCode = parsed.error;
}

const numericCode = Number(apiErrorCode);
const ok = !nodeError && numericCode === 0;
const requestId = parsed?.data?.request_id || sms?.data?.request_id || '';
const apiMessage = nodeError
  ? (sms.error.message || sms.error.name || 'HTTP request failed')
  : (parsed?.msg || sms?.msg || '');

let privateNote = '';

if (ok) {
  privateNote = 'Message sent successfully.';
  if (requestId) privateNote += `\nRequest ID: ${requestId}`;
} else {
  const meaning = errorMessages[numericCode] || apiMessage || 'Unknown error.';
  const codeText = apiErrorCode === undefined || apiErrorCode === null || apiErrorCode === '' ? 'N/A' : apiErrorCode;
  privateNote = `Message send failed.\nError ${codeText}: ${meaning}`;
  if (apiMessage && apiMessage !== meaning) privateNote += `\nAPI Message: ${apiMessage}`;
}

// Add local validation warnings only when useful.
if (original.missingConfig?.length) {
  privateNote += `\nMissing/placeholder config: ${original.missingConfig.join(', ')}`;
}
if (!original.validBangladeshMobile) {
  privateNote += '\nWarning: Phone number does not look like a valid Bangladesh mobile number.';
}

const chatwootMessagePayload = {
  content: privateNote,
  message_type: 'outgoing',
  private: true,
  content_type: 'text'
};

return [
  {
    json: {
      ...original,
      smsbdResponse: parsed,
      privateNote,
      chatwootMessagePayload
    }
  }
];
